257 func (s *Store) shouldExtendPayload(fn *PayloadNode) bool {
258         if fn == nil {
259                 return false
260         }
261         n := fn.node
262         if n.payloadAvailabilityVote.Count() > fieldparams.PTCSize/2 && n.payloadDataAvailabilityVote.Count() > fieldparams.PTCSize/2 {
263                 return true
264         }
265         if s.proposerBoostRoot == [32]byte{} {
266                 return true
267         }
268         pn := s.emptyNodeByRoot[s.proposerBoostRoot]
269         if pn == nil {
270                 return true
271         }
272         if pn.node.parent.node != fn.node {
273                 return true
274         }
275         return pn.node.parent.full
276 }
