278 // choosePayloadContent chooses between empty or full for the passed consensus node.
279 func (s *Store) choosePayloadContent(n *Node) *PayloadNode {
280         if n == nil {
281                 return nil
282         }
283         fn := s.fullNodeByRoot[n.root]
284         en := s.emptyNodeByRoot[n.root]
285         if fn == nil {
286                 return en
287         }
288         if fn.weight > en.weight {
289                 return fn
290         } else if fn.weight < en.weight {
291                 return en
292         }
293         previousSlot := n.slot+1 == s.currentSlot()
294         if !previousSlot || s.shouldExtendPayload(fn) {
295                 return fn
296         }
297         return en
298 }
